object Solution { def reconcile_inventory(expected: Map[String, Any], observed: Map[String, Any]): Seq[Seq[Any]] = { (expected.keySet ++ observed.keySet).toSeq.sorted.flatMap { sku => val inExpected = expected.contains(sku); val inObserved = observed.contains(sku); val expQty = expected.get(sku).map(asInt).getOrElse(0); val obsQty = observed.get(sku).map(asInt).getOrElse(0); val delta = obsQty - expQty; if (!inObserved) Some(Seq(sku, "missing", expQty, 0, delta)) else if (!inExpected) Some(Seq(sku, "extra", 0, obsQty, delta)) else if (obsQty < expQty) Some(Seq(sku, "short", expQty, obsQty, delta)) else if (obsQty > expQty) Some(Seq(sku, "over", expQty, obsQty, delta)) else None } }; private def asInt(value: Any): Int = value match { case n: Int => n; case n: Long => n.toInt; case n: Double => n.toInt; case _ => 0 } }
